CREATE AGGREGATE sum_by_group(val INTEGER)
RETURNS INTEGER
LANGUAGE PYTHON {
    unique = numpy.unique(aggr_group)
    total = numpy.zeros(shape=(unique.size))
    for i in range(unique.size):
        total[i] = numpy.sum(val[aggr_group==unique[i]])
    return numpy.sum(total)
};

CREATE AGGREGATE avg_by_group(val INTEGER)
RETURNS FLOAT
LANGUAGE PYTHON {
    unique = numpy.unique(aggr_group)
    total = numpy.zeros(shape=(unique.size))
    count = numpy.zeros(shape=(unique.size))
    for i in range(unique.size):
        total[i] = numpy.sum(val[aggr_group==unique[i]])
        count[i] = numpy.count_nonzero(aggr_group==unique[i])
    return numpy.sum(total) / numpy.sum(count)
};

CREATE AGGREGATE max_value(val INTEGER)
RETURNS INTEGER
LANGUAGE C {
    int max = -1;
    for(int i=0; i < aggr_count; i++) {
        if(val[i] > max) {
            max = val[i];
        }
    }
    return max;
};

CREATE AGGREGATE min_value(val INTEGER)
RETURNS INTEGER
LANGUAGE C++ {
    int min = INT_MAX;
    for(int i=0; i < aggr_count; i++) {
        if(val[i] < min) {
            min = val[i];
        }
    }
    return min;
};

CREATE AGGREGATE concat_values(val VARCHAR)
RETURNS VARCHAR
LANGUAGE R {
    return(paste(val, collapse=' '))
};

CREATE AGGREGATE count_distinct(val INTEGER)
RETURNS INTEGER
LANGUAGE PYTHON {
    return len(numpy.unique(val))
};

CREATE AGGREGATE total_sum_by_group(val INTEGER)
RETURNS INTEGER
LANGUAGE PYTHON {
    try:
        return numpy.sum(val)
    except:
        return 0
};
